"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[886],{886:function(a,i,e){e.r(i),i.default={metadata:{title:"Miejska Mapa Wydarzeń",description:"Miejska Mapa Wydarzeń - Strona gł\xf3wna",keywords:"wydarzenia, wydarzenia w mieście, mapa, produkt, software, oprogramowanie"},page_sections:{home:{title:"Miejska Mapa Wydarzeń",slogan:"Zrewolucjonizuj zarządzanie wydarzeniami w mieście"},traits:{trait_1:{title:"Przegląd miejskiego życia",text:"Centrum informacji o wydarzeniach w mieście, łatwo dostępne dla każdego."},trait_2:{title:"Łatwy dostęp do informacji",text:"Możliwość filtrowania wydarzeń po nazwach, typach, datach i lokalizacjach."},trait_3:{title:"Błyskawiczna komunikacja",text:"Natychmiastowy kontakt definiujący nowy standard relacji samorząd-mieszkańcy."}},about:{title:"O Mapie",text:"Miejska Mapa Wydarzeń to innowacyjna platforma cyfrowa, dostępna zar\xf3wno w formie aplikacji internetowej, jak i mobilnej, stworzona z myślą o podniesieniu jakości życia mieszkańc\xf3w miast. \nKonsoliduje informacje o lokalnych wydarzeniach kulturalnych, utrudnieniach drogowych, przerwach w dostawie usług, zagrożeniach i innych istotnych zdarzeniach w mieście. \nUmożliwia to nie tylko łatwiejsze planowanie codziennego życia dzięki prostemu dostępowi do wszystkich informacji, \nale także redukuje nieporozumienia i pomaga użytkownikom zorientować się w bogatej ofercie wydarzeń miejskich, zwiększając tym samym ich widoczność. \nMiejska Mapa Wydarzeń pełni r\xf3wnież funkcję kluczowego kanału komunikacji między władzami miasta a jego mieszkańcami, \npromując transparentność i efektywność w przekazywaniu informacji w ramach społeczności.\n"},call_to_action:{title:"Dzięki Miejskiej Mapie Wydarzeń te problemy to przeszłość! Zainteresowany?",text:"Skontaktuj się z nami i dowiedz się, jak Miejska Mapa Wydarzeń może pom\xf3c w rozwoju Twojego miasta.",button_text:"Um\xf3w prezentację"},problems:{title:"Problemy miast",problem_1:{title:"Rozproszone źr\xf3dła informacji",text:"Brak zcentralizowanych informacji wymusza na mieszkańcach konieczność przeszukiwania wielu r\xf3żnych (niekoniecznie moderowanych) źr\xf3deł, co sprawia, że trudno jest im uzyskać kompletny obraz wydarzeń w ich mieście."},problem_2:{title:"Niedostateczna widoczność wydarzeń i inicjatyw",text:"Wielu mieszkańc\xf3w może być nieświadomych lokalnych wydarzeń oraz inicjatyw społecznych, co ogranicza ich aktywne uczestnictwo w życiu lokalnej społeczności."},problem_3:{title:"Brak skutecznej komunikacji",text:"Zaniedbanie efektywnej komunikacji między władzami miasta a jego mieszkańcami prowadzi do zwiększenia dystansu pomiędzy nimi, co wpływa negatywnie na transparentność działań lokalnych władz, a także szybkość rozwiązywania problem\xf3w i podejmowania decyzji."},problem_4:{title:"Nadmierne obciążenie urzędnik\xf3w",text:"Konieczność reagowania na nagłe sytuacje, takie jak przerwy w dostawie wody czy prądu, pochłania dużo czasu pracownik\xf3w urzęd\xf3w miast i instytucji miejskich, kt\xf3ry m\xf3głby być spożytkowany na inne istotne działania."}},benefits:{title:"Korzyści",subsection_1:{title:"Korzyści dla mieszkańc\xf3w",benefit_1:{title:"Przejrzystość",point_1:{title:"Centralizacja informacji: ",text:"Wszystko w jednym miejscu - czytelność i oszczędność czasu."},point_2:{title:"Podniesiona świadomość: ",text:"Łatwy dostęp do aktualnych informacji oraz pilnych komunikat\xf3w zwiększa świadomość społeczności lokalnej."}},benefit_2:{title:"Planowanie",point_1:{title:"Szybki dostęp do aktualnych danych: ",text:"Informacje o awariach, wydarzeniach, utrudnieniach i zagrożeniach w zasięgu ręki."},point_2:{title:"Poprawa jakości życia: ",text:"Efektywne zarządzanie czasem i unikanie problem\xf3w dzięki możliwości szybszego, a także lepszego planowania działań."}},benefit_3:{title:"Społeczność",point_1:{title:"Wzmocnienie więzi społecznych: ",text:"Inspiracja do budowania relacji międzyludzkich poprzez uczestnictwo w wydarzeniach i inicjatywach."},point_2:{title:"Zachęta do uczestnictwa w życiu miasta: ",text:"Popularyzacja zaangażowania w lokalne inicjatywy i wydarzenia dzięki łatwiejszemu dostępowi do informacji na ich temat."}}},subsection_2:{title:"Korzyści dla samorząd\xf3w",benefit_1:{title:"Komunikacja",point_1:{title:"Zwiększone zaufanie: ",text:"Transparentność i otwartość relacji, przyczyniające sie do budowania zaufania pomiędzy mieszkańcami a władzami miejskimi."},point_2:{title:"Efektywne rozpowszechnianie informacji: ",text:"Szybkie i skuteczne docieranie do szerokiej grupy odbiorc\xf3w umożliwiające lepszą komunikację oraz większe zaangażowanie mieszkańc\xf3w."}},benefit_2:{title:"Zarządzanie",point_1:{title:"Ograniczenie dezinformacji: ",text:"Oficjalna miejska mapa pozwala na kontrolę nad przekazem informacji, co przyczynia się do zmniejszenia chaosu informacyjnego."},point_2:{title:"Efektywne wykorzystanie zasob\xf3w:",text:"Większa transparentność polepsza efektywność samorządu poprzez łatwiejsze zarządzanie zasobami miejskimi oraz środkami finansowymi."}},benefit_3:{title:"Innowacja",point_1:{title:"Przyspiesznie proces\xf3w: ",text:"Cyfryzacja i nowoczesne rozwiązanie technologiczne przyspieszające procesy administracyjne, rozwojowe, a także wzrost gospodarczy."},point_2:{title:"Wzrost atrakcyjności miasta: ",text:"Budowanie modelowego miasta przyszłości zwiększa jego atrakcyjność dla mieszkańc\xf3w, turyst\xf3w oraz potencjalnych inwestor\xf3w."}}}},contact:{title:"Kontakt",text_1:"Skontaktuj się z nami",text_2:"Popraw jakość życia mieszkańc\xf3w",text_3:"Masz pytania? Chcesz dowiedzieć się więcej? Chętnie pomożemy! \\n\nSkontaktuj się z naszym zespołem w celu om\xf3wienia, jak Miejska Mapa Wydarzeń może wspierać Twoje miasto.\\n\nZachęcamy do bezpośredniego kontaktu, aby um\xf3wić się na prezentację lub rozmowę z naszym specjalistą.\n"}}}}}]);